// Inline definitions from headers to avoid missing files
#define REC_LENGTH 49

typedef struct {
    float lat;
    float lng;
} LatLong;

typedef struct {
    char recString[REC_LENGTH];
    float distance;
} Record;

typedef double cl_time;

// Utility functions inline
void* alloc(size_t size) {
    void* ptr = NULL;
    ptr = malloc(size);
    if(ptr == NULL) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

int cl_errChk(cudaError_t status, const char * msg, bool exitOnErr) {
    if(status != cudaSuccess) {
        printf("CUDA Error: %d %s %s\n", (int)status, cudaGetErrorString(status), msg);
        if(exitOnErr) {
            exit(-1);
        }
        return true;
    }
    return false;
}

void gettimeofday(struct timeval *tv, struct timezone *tz) {
    struct timeval curTime;
    gettimeofday(&curTime, NULL);
    tv->tv_sec = curTime.tv_sec;
    tv->tv_usec = curTime.tv_usec;
    if (tz) {
        tz->tz_minuteswest = 0;
        tz->tz_dsttime = 0;
    }
}

void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *r) {
    r->tv_sec = t1->tv_sec - t2->tv_sec;
    r->tv_usec = t1->tv_usec - t2->tv_usec;
    if (r->tv_usec < 0) {
        r->tv_sec--;
        r->tv_usec += 1000000;
    }
}

// CUDA Kernel equivalent to OpenCL NearestNeighbor
__global__ void NearestNeighbor(LatLong *d_locations,
                                float *d_distances,
                                const int numRecords,
                                const float lat,
                                const float lng) {
    int globalId = threadIdx.x + blockDim.x * blockIdx.x;

    if (globalId < numRecords) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        *dist = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) + 
                            (lng - latLong->lng) * (lng - latLong->lng));
    }
}

// CUDA version of cl_init_context (simplified for single device)
cudaError_t cuda_init_context(int platform, int dev, int quiet) {
    int deviceCount = 0;
    cudaError_t error_id = cudaGetDeviceCount(&deviceCount);

    if (error_id != cudaSuccess) {
        printf("cudaGetDeviceCount returned %d\n->%s\n", (int)error_id, cudaGetErrorString(error_id));
        exit(-1);
    }

    if (deviceCount == 0) {
        printf("There are no available device(s) that support CUDA\n");
        exit(-1);
    }

    if (!quiet) {
        printf("Number of CUDA devices detected: %d\n", deviceCount);
        for (int i = 0; i < deviceCount; i++) {
            cudaDeviceProp_t prop;
            cudaGetDeviceProperties(&prop, i);
            printf("Device %d: %s\n", i, prop.name);
        }
    }

    int chosen_device = 0;
    if (dev >= 0 && dev < deviceCount) {
        chosen_device = dev;
    }

    if (!quiet) {
        printf("Using Device %d\n", chosen_device);
    }

    error_id = cudaSetDevice(chosen_device);
    cl_errChk(error_id, "Setting device", true);

    return error_id;
}

void cuda_cleanup() {
    cudaDeviceReset();
}

// Main application logic translated from OpenCL to CUDA
char *data_folder;

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist: %s\n", filename);
        exit(0);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            if (fgets(record.recString, 49, fp) == NULL) break;
            fgetc(fp); // consume newline if present or handle logic

            // Check for EOF or empty line after fgets
            if (feof(fp)) break;

            char substr[6];
            for (i = 0; i < 5; i++) {
                if (strlen(record.recString) > 28 + i) substr[i] = *(record.recString + i + 28);
                else substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5; i++) {
                if (strlen(record.recString) > 33 + i) substr[i] = *(record.recString + i + 33);
                else substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
            case 'r':
                i++;
                *r = atoi(argv[i]);
                break;
            case 'l':
                if (argv[i][2] == 'a') {
                    *lat = atof(argv[i + 1]);
                } else {
                    *lng = atof(argv[i + 1]);
                }
                i++;
                break;
            case 'h':
                return 1;
                break;
            case 'q':
                *q = 1;
                break;
            case 't':
                *t = 1;
                break;
            case 'p':
                i++;
                *p = atoi(argv[i]);
                break;
            case 'd':
                i++;
                *d = atoi(argv[i]);
                break;
            case 'f':
                i++;
                data_folder = argv[i];
                break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

