}

float *CUDAFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat,
    float lng,
    int timing) {

    cudaError_t status;
    LatLong *d_locations;
    float *d_distances;
    cudaEvent_t writeEvent, kernelEvent, readEvent;

    // Timing variables
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    // Initialize CUDA
    cuda_init_context(-1, -1, 1); // quiet mode for internal call
#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    status = cudaMalloc((void**)&d_locations, sizeof(LatLong) * numRecords);
    cl_errChk(status, "creating buffer locations", true);

    status = cudaMalloc((void**)&d_distances, sizeof(float) * numRecords);
    cl_errChk(status, "creating buffer distances", true);
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Create events
    cudaEventCreate(&writeEvent);
    cudaEventCreate(&kernelEvent);
    cudaEventCreate(&readEvent);

    // Copy data to device (Write)
#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    status = cudaMemcpyAsync(d_locations, &locations[0], sizeof(LatLong) * numRecords, cudaMemcpyHostToDevice);
    cl_errChk(status, "Writing buffer", true);
    cudaEventRecord(writeEvent);
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
#endif

    // Setup kernel arguments and launch
    int blockSize = 64;
    int numBlocks = (numRecords + blockSize - 1) / blockSize;

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif
    NearestNeighbor<<<numBlocks, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);
    status = cudaGetLastError();
    cl_errChk(status, "ERROR in Executing Kernel NearestNeighbor", true);
    cudaEventRecord(kernelEvent);
#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
#endif

    // Copy data back to host (Read)
    float *distances = (float *)malloc(sizeof(float) * numRecords);
#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    status = cudaMemcpyAsync(distances, d_distances, sizeof(float) * numRecords, cudaMemcpyDeviceToHost);
    cl_errChk(status, "ERROR with cudaMemcpy", true);
    cudaEventRecord(readEvent);
    cudaEventSynchronize(readEvent); // Ensure completion
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
#endif

    if (timing) {
#ifdef TIMING
        float writeTime, kernelTime, readTime;
        printf("# Records\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%d        \t", numRecords);

        cudaEventElapsedTime(&writeTime, writeEvent, writeEvent); // Dummy, need separate events or use timestamps
        // Since we used gettimeofday for surrounding blocks in the original, let's use those for consistency with the "timing" block logic if possible, 
        // but the original OpenCL code used Event Profiling. 
        // To mimic the OpenCL event profiling output exactly using CUDA events:

        float eventStart, eventEnd; // CUDA events don't give absolute start/end like OpenCL profiling easily without extra work, 
        // but we can measure durations. The original code prints durations.

        // Let's calculate durations from the recorded events relative to each other if we chain them, 
        // but here they are recorded sequentially.
        // Actually, the original OpenCL code calculates: (end - start).
        // In CUDA, cudaEventElapsedTime gives duration between two events.
        // We need to record start and stop for each phase properly.
        // Refining the event recording above:

        // Re-calculating based on the structure:
        // Write happened before kernel, kernel before read.
        // We need specific start/stop events for each phase to get individual times.
        // Let's assume the previous recording points were intended as markers.
        // To strictly follow the output format, we will use the gettimeofday deltas calculated below 
        // if the 'timing' flag relies on the host timers, OR use CUDA events if we restructure.
        // The original code uses clGetEventProfilingInfo. 
        // Let's use CUDA events properly for the three phases.

        cudaEvent_t writeStart, writeStop, kernelStart, kernelStop, readStart, readStop;
        cudaEventCreate(&writeStart); cudaEventCreate(&writeStop);
        cudaEventCreate(&kernelStart); cudaEventCreate(&kernelStop);
        cudaEventCreate(&readStart); cudaEventCreate(&readStop);

        // Re-run logic mentally for timing:
        // Write
        cudaEventRecord(writeStart);
        cudaMemcpyAsync(d_locations, &locations[0], sizeof(LatLong) * numRecords, cudaMemcpyHostToDevice);
        cudaEventRecord(writeStop);

        // Kernel
        cudaEventRecord(kernelStart);
        NearestNeighbor<<<numBlocks, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);
        cudaEventRecord(kernelStop);

        // Read
        cudaEventRecord(readStart);
        cudaMemcpyAsync(distances, d_distances, sizeof(float) * numRecords, cudaMemcpyDeviceToHost);
        cudaEventRecord(readStop);

        cudaEventSynchronize(readStop);

        float w_time, k_time, r_time;
        cudaEventElapsedTime(&w_time, writeStart, writeStop);
        cudaEventElapsedTime(&k_time, kernelStart, kernelStop);
        cudaEventElapsedTime(&r_time, readStart, readStop);

        printf("%f [%.2fMB]\t", w_time / 1000.0, (float)((sizeof(LatLong) * numRecords) / 1e6));
        printf("%f\t", k_time / 1000.0);
        printf("%f [%.2fMB]\t", r_time / 1000.0, (float)((sizeof(float) * numRecords) / 1e6));
        printf("%f\n\n", (w_time + k_time + r_time) / 1000.0);

        h2d_time = w_time;
        kernel_time = k_time;
        d2h_time = r_time;
#endif
    }

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(d_locations);
    cudaFree(d_distances);
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    // Recalculate total time if needed, or use event sums
    // The original code uses total_time = close_end - total_start
    gettimeofday(&tv_total_end, NULL);
    tvsub(&tv_total_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    cudaEventDestroy(writeEvent);
    cudaEventDestroy(kernelEvent);
    cudaEventDestroy(readEvent);

    return distances;
}

int main(int argc, char *argv[]) {
    std::vector<Record> records;
    float *recordDistances;

    std::vector<LatLong> locations;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, records, locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    recordDistances = CUDAFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }
    free(recordDistances);
    cuda_cleanup();
    return 0;
}
